scwin.f_Retrieve = async function () {
  let chkwrkplcd = ed_wrkPlCd.getValue();
  if ($c.gus.cfIsNull($p, chkwrkplcd)) {
    await $c.win.alert($p, "작업장 코드는 필수 입력 항목입니다.");
    ed_wrkPlCd.focus();
    return;
  }

  // 필수항목 체크
  let chk11 = await $c.gus.cfValidate($p, [tb_queryList]);
  if (!chk11) {
    return false;
  }
  if (!$c.gus.cfIsAfterDate($p, ed_crryinoutTermFrom.getValue(), ed_crryinoutTermTo.getValue())) {
    $c.gus.cfAlertMsg($p, MSG_CM_ERR_039); // 시작일자를 종료일 이전으로 선택[입력]하여 주십시오.
    ed_srchWrkStDt.focus();
    return;
  }
  var cheVal = "";
  if (ckWrkPlCd.checked) {
    cheVal = "1";
  } else {
    cheVal = "0";
  }

  // dma_retrieve.set("wrkPl", ed_wrkPlCd.getValue());
  dma_retrieve.set("wrkPl", ed_wrkPlCd.getValue());
  dma_retrieve.set("crryinoutTermFrom", ed_crryinoutTermFrom.getValue());
  dma_retrieve.set("crryinoutTermTo", ed_crryinoutTermTo.getValue());
  dma_retrieve.set("mrn", ed_mrn.getValue());
  dma_retrieve.set("msn", ed_msn.getValue() == "" ? -1 : ed_msn.getValue());
  dma_retrieve.set("hsn", ed_hsn.getValue() == "" ? -1 : ed_hsn.getValue());
  dma_retrieve.set("ckWrkPlCd", cheVal);
  dma_retrieve.set("blNo", ed_blNo.getValue());
  dma_retrieve.set("cntrBulk", scwin.cntrBulk);
  debugger;
  if (dma_retrieve.get("crryinoutCls") == "all") {
    dma_retrieve.set("crryinoutCls", "");
  } else {
    dma_retrieve.set("crryinoutCls", acb_crryinoutCls.getValue());
  }
  if (dma_retrieve.get("sndClsCd") == "all") {
    dma_retrieve.set("sndClsCd", "");
  } else {
    dma_retrieve.set("sndClsCd", acb_sndCls.getValue());
  }
  $c.sbm.execute($p, sbm_retrieve);
};

